#include<cstdio>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void print(const int &p){if(p>9)print(p/10);putchar(p%10+'0');}
inline void pt(const int &x,const char &c='\n'){print(x<0?putchar('-'),-x:x);putchar(c);}
const int N=1e5+10,Mod=51061;int n;
template <typename T> inline void DN(T &x){x>=Mod?x-=Mod:T();}
template <typename T> inline void Swap(T&x,T&y){T t=x;x=y;y=t;}
inline char Get(){char x;do x=getchar();while(x!='*'&&x!='+'&&x!='/'&&x!='-');return x;}
namespace LCT
{
	int ch[N][2],fa[N],sm[N],ad[N],ml[N],sz[N],vl[N];bool tg[N];
	inline void update(int x)
	{
		DN(sm[x]=sm[ch[x][0]]+sm[ch[x][1]]);DN(sm[x]+=vl[x]);
		sz[x]=sz[ch[x][0]]+sz[ch[x][1]]+1;
	}
	inline void Rev(int x){Swap(ch[x][0],ch[x][1]);tg[x]^=1;}
	inline void Mul(int x,int v)
	{
		sm[x]=1ll*sm[x]*v%Mod;vl[x]=1ll*vl[x]*v%Mod;
		ad[x]=1ll*ad[x]*v%Mod;ml[x]=1ll*ml[x]*v%Mod;
	}
	inline void Add(int x,int v){DN(sm[x]+=1ll*sz[x]*v%Mod);DN(vl[x]+=v);DN(ad[x]+=v);}
	inline void pushdown(int x)
	{
		if(tg[x]){Rev(ch[x][0]);Rev(ch[x][1]);tg[x]=false;}
		if(ml[x]!=1){Mul(ch[x][0],ml[x]);Mul(ch[x][1],ml[x]);ml[x]=1;}
		if(ad[x]){Add(ch[x][0],ad[x]);Add(ch[x][1],ad[x]);ad[x]=0;}
	}
	inline bool nrt(const int &x){return ch[fa[x]][0]==x||ch[fa[x]][1]==x;}
	inline void rotate(int x)
	{
		int y=fa[x],z=fa[y];bool k=ch[y][1]==x;
		if(nrt(y))ch[z][ch[z][1]==y]=x;int w=ch[x][!k];ch[ch[x][!k]=y][k]=w;
		if(w)fa[w]=y;fa[fa[y]=x]=z;update(y);
	}
	inline void pushall(int x){if(nrt(x))pushall(fa[x]);pushdown(x);}
	inline void splay(int x)
	{
		pushall(x);const int &y=fa[x];
		while(nrt(x)){nrt(y)?rotate((ch[fa[y]][0]==y)^(ch[y][0]==x)?x:y):void(),rotate(x);}update(x);
	}
	inline void access(int x){for(int y=0;x;x=fa[y=x])splay(x),ch[x][1]=y,update(x);}
	inline void makeRt(int x){access(x);splay(x);Rev(x);}
	inline void split(int x,int y){makeRt(x);access(y);splay(y);}
	inline void lnk(int x,int y){makeRt(x);fa[x]=y;}
	inline void cut(int x,int y){split(x,y);fa[x]=ch[y][0]=0;}
	inline void mul(int x,int y,int v){split(x,y);Mul(y,v);}
	inline void add(int x,int y,int v){split(x,y);Add(y,v);}
	inline int qry(int x,int y){split(x,y);return sm[y];}
}
using LCT::lnk;using LCT::cut;using LCT::qry;using LCT::add;using LCT::mul;
int main()
{
	n=read();int Q=read();rep(1,n,i)LCT::sz[i]=LCT::vl[i]=LCT::ml[i]=1;
	rep(2,n,i){int x=read(),y=read();lnk(x,y);}
	int x,y;while(Q--)switch(Get())
	{
		case '+': x=read();y=read();add(x,y,read());break;
		case '-': x=read();y=read();cut(x,y);x=read();y=read();lnk(x,y);break;
		case '*': x=read();y=read();mul(x,y,read());break;
		case '/': x=read();y=read();pt(qry(x,y));break;
	}
}
